import { Component } from '@angular/core';

interface Slide {
  id: number;
  title: string;
  imageUrl: string;
}

@Component({
  selector: 'app-root',
  standalone: true,
  template: `
    <main class="app">
      <section class="card">
        <h1>Image Slider</h1>

        @if (currentSlide; as slide) {
          <figure class="frame">
            <img class="image" [src]="slide.imageUrl" [alt]="slide.title" />
            <figcaption class="caption">{{ slide.title }}</figcaption>
          </figure>
        }

        <div class="meta">
          Slide {{ currentIndex + 1 }} of {{ totalSlides }}
        </div>

        <div class="actions">
          <button (click)="prev()" [disabled]="!canGoPrev">Previous</button>
          <button (click)="next()" [disabled]="!canGoNext">Next</button>
        </div>

        <div class="dots">
          @for (slide of slides; track slide.id; let i = $index) {
            <button
            type="button"
            class="dot"
            [class.active]="i === currentIndex"
            (click)="goTo(i)"
            aria-label="Go to slide {{ i + 1 }}"
            ></button>
          }
        </div>
      </section>
    </main>
  `,
  styles: [
    `.app{min-height:100vh;display:grid;place-items:center;background:#0a0a0a;color:#e5e7eb;}`,
    `.card{width:100%;max-width:520px;padding:16px 20px;background:#0b1020;border-radius:12px;border:1px solid #1f2937;display:grid;gap:12px;}`,
    `.frame{margin:0;border-radius:12px;overflow:hidden;border:1px solid #1f2937;background:#020617;}`,
    `.image{display:block;width:100%;height:240px;object-fit:cover;}`,
    `.caption{padding:8px 12px;font-size:14px;color:#e5e7eb;background:rgba(15,23,42,.9);}`,
    `.meta{font-size:12px;color:#9ca3af;text-align:center;}`,
    `.actions{display:flex;gap:8px;justify-content:center;}`,
    `button{padding:8px 14px;border-radius:10px;border:none;cursor:pointer;font-weight:600;background:#a3e635;color:#111;}`,
    `button[disabled]{opacity:.5;cursor:not-allowed;}`,
    `.dots{display:flex;justify-content:center;gap:6px;margin-top:4px;}`,
    `.dot{width:8px;height:8px;border-radius:999px;border:none;background:#374151;cursor:pointer;}`,
    `.dot.active{background:#a3e635;}`
  ]
})
export class AppComponent {
  readonly slides: Slide[] = [
    {
      id: 1,
      title: 'Snowflakes glowing under city lights',
      imageUrl: 'https://images.pexels.com/photos/46253/pexels-photo-46253.jpeg'
    },
    {
      id: 2,
      title: 'Forest trail in the morning',
      imageUrl: 'https://images.pexels.com/photos/1563604/pexels-photo-1563604.jpeg'
    },
    {
      id: 3,
      title: 'City lights at night',
      imageUrl: 'https://images.pexels.com/photos/220067/pexels-photo-220067.jpeg'
    }
  ];

  currentIndex = 0;

  get totalSlides(): number {
    return this.slides.length;
  }

  get currentSlide(): Slide | null {
    return this.slides[this.currentIndex] ?? null;
  }

  get canGoPrev(): boolean {
    return this.currentIndex > 0;
  }

  get canGoNext(): boolean {
    return this.currentIndex < this.totalSlides - 1;
  }

  goTo(index: number): void {
    if (index < 0 || index >= this.totalSlides) return;
    this.currentIndex = index;
  }

  prev(): void {
    if (this.canGoPrev) {
      this.currentIndex--;
    }
  }

  next(): void {
    if (this.canGoNext) {
      this.currentIndex++;
    }
  }
}
